# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that manages users, projects,
tasks, messaging, performance analytics and exportable reports.

The public surface (classes, enums, exceptions and the
``TeamCollaborationManager`` facade) is exercised by ``test_solution.py``.

Design notes
------------
* All mutable state lives in a single shared ``_Context`` object that owns one
  re-entrant lock.  Every repository (``users``, ``projects``, ``tasks``,
  ``messages``, ``performance``, ``reports``) shares that exact lock instance so
  the whole manager is guarded by one mutex -- this keeps cross-entity
  invariants (id generation, assignee indexes, cascades) consistent under
  concurrency.
* Public read methods always return deep copies so callers can never mutate the
  internal store by holding on to a returned object or list.
* Standard library only, ASCII only.
"""

from __future__ import annotations

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Callable, Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(enum.Enum):
    """Authorization roles for a user."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(enum.Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Identifies the kind of report payload."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing related state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A member of the workspace."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A time-boxed body of work owned by a user."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    """A unit of work that lives inside a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A comment posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """Peer feedback from one user about another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Shared context
# ---------------------------------------------------------------------------
def _default_now() -> datetime:
    return datetime.now()


class _Context:
    """Holds every shared store, the global id counter and the single lock."""

    def __init__(self, now: Optional[Callable[[], datetime]]):
        self.lock = threading.RLock()
        self.now: Callable[[], datetime] = now if now is not None else _default_now

        self._id = 0
        self._rating_id = 0

        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: List[Rating] = []

        # Secondary indexes.
        self.assignee_index: Dict[int, Set[int]] = {}
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}

    # -- id generation -----------------------------------------------------
    def next_id(self) -> int:
        self._id += 1
        return self._id

    def next_rating_id(self) -> int:
        self._rating_id += 1
        return self._rating_id

    # -- lookups -----------------------------------------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # -- assignee index helpers -------------------------------------------
    def index_assign(self, user_id: int, task_id: int) -> None:
        self.assignee_index.setdefault(user_id, set()).add(task_id)

    def index_unassign(self, user_id: Optional[int], task_id: int) -> None:
        if user_id is None:
            return
        bucket = self.assignee_index.get(user_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                del self.assignee_index[user_id]

    def tasks_for_assignee(self, user_id: int) -> List[Task]:
        task_ids = self.assignee_index.get(user_id, set())
        tasks = [self.tasks[tid] for tid in task_ids if tid in self.tasks]
        tasks.sort(key=lambda t: t.id)
        return tasks


def _clone(obj):
    """Return a deep copy so callers cannot mutate internal state."""

    return copy.deepcopy(obj)


def _clone_list(items) -> list:
    return [copy.deepcopy(item) for item in items]


# ---------------------------------------------------------------------------
# Repositories
# ---------------------------------------------------------------------------
class _BaseStore:
    def __init__(self, ctx: _Context):
        self._ctx = ctx
        self._lock = ctx.lock


class _UserStore(_BaseStore):
    @staticmethod
    def _validate_email(email: str) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        return cleaned

    @staticmethod
    def _validate_username(username: str) -> str:
        if not isinstance(username, str):
            raise ValidationError("username must be a string")
        cleaned = username.strip()
        if not cleaned:
            raise ValidationError("username must not be empty")
        return cleaned

    def register(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            uname = self._validate_username(username)
            mail = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if uname in self._ctx.username_index:
                raise DuplicateError("username already in use")
            if mail in self._ctx.email_index:
                raise DuplicateError("email already in use")

            user = User(
                id=self._ctx.next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._ctx.now(),
            )
            self._ctx.users[user.id] = user
            self._ctx.username_index[uname] = user.id
            self._ctx.email_index[mail] = user.id
            return _clone(user)

    def get(self, user_id) -> User:
        with self._lock:
            return _clone(self._ctx.require_user(user_id))

    def list(self) -> List[User]:
        with self._lock:
            users = sorted(self._ctx.users.values(), key=lambda u: u.id)
            return _clone_list(users)

    def update(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._ctx.require_user(user_id)

            new_username = None
            new_email = None
            if username is not None:
                new_username = self._validate_username(username)
                owner = self._ctx.username_index.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already in use")
            if email is not None:
                new_email = self._validate_email(email)
                owner = self._ctx.email_index.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already in use")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_username is not None:
                self._ctx.username_index.pop(user.username, None)
                user.username = new_username
                self._ctx.username_index[new_username] = user_id
            if new_email is not None:
                self._ctx.email_index.pop(user.email, None)
                user.email = new_email
                self._ctx.email_index[new_email] = user_id
            if role is not None:
                user.role = role
            return _clone(user)

    def delete(self, user_id) -> None:
        with self._lock:
            user = self._ctx.require_user(user_id)

            for project in self._ctx.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task_id in self._ctx.assignee_index.get(user_id, set()):
                task = self._ctx.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")

            self._ctx.assignee_index.pop(user_id, None)
            self._ctx.username_index.pop(user.username, None)
            self._ctx.email_index.pop(user.email, None)
            del self._ctx.users[user_id]


class _ProjectStore(_BaseStore):
    def create(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must not be empty")
            if start_date is None or end_date is None:
                raise ValidationError("project dates are required")
            if end_date < start_date:
                raise ValidationError("end date must not precede start date")
            self._ctx.require_user(owner_id)

            project = Project(
                id=self._ctx.next_id(),
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._ctx.now(),
            )
            self._ctx.projects[project.id] = project
            return _clone(project)

    def get(self, project_id) -> Project:
        with self._lock:
            return _clone(self._ctx.require_project(project_id))

    def list(self) -> List[Project]:
        with self._lock:
            projects = sorted(self._ctx.projects.values(), key=lambda p: p.id)
            return _clone_list(projects)

    def update(self, project_id, name=None, start_date=None,
               end_date=None, description=None) -> Project:
        with self._lock:
            project = self._ctx.require_project(project_id)

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name must not be empty")

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end date must not precede start date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete(self, project_id) -> None:
        with self._lock:
            self._ctx.require_project(project_id)

            task_ids = [
                tid for tid, task in self._ctx.tasks.items()
                if task.project_id == project_id
            ]
            for task_id in task_ids:
                task = self._ctx.tasks[task_id]
                self._ctx.index_unassign(task.assignee_id, task_id)
                msg_ids = [
                    mid for mid, msg in self._ctx.messages.items()
                    if msg.task_id == task_id
                ]
                for mid in msg_ids:
                    del self._ctx.messages[mid]
                del self._ctx.tasks[task_id]

            project_msg_ids = [
                mid for mid, msg in self._ctx.messages.items()
                if msg.project_id == project_id
            ]
            for mid in project_msg_ids:
                del self._ctx.messages[mid]

            del self._ctx.projects[project_id]


class _TaskStore(_BaseStore):
    def create(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must not be empty")
            project = self._ctx.require_project(project_id)
            if assignee_id is not None:
                self._ctx.require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task = Task(
                id=self._ctx.next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._ctx.now(),
            )
            self._ctx.tasks[task.id] = task
            if assignee_id is not None:
                self._ctx.index_assign(assignee_id, task.id)
            return _clone(task)

    def get(self, task_id) -> Task:
        with self._lock:
            return _clone(self._ctx.require_task(task_id))

    def list_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = [
                task for task in self._ctx.tasks.values()
                if task.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return _clone_list(tasks)

    def list_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._ctx.require_user(assignee_id)
            return _clone_list(self._ctx.tasks_for_assignee(assignee_id))

    def assign(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(assignee_id)
            if task.assignee_id != assignee_id:
                self._ctx.index_unassign(task.assignee_id, task_id)
                task.assignee_id = assignee_id
                self._ctx.index_assign(assignee_id, task_id)
            return _clone(task)

    def reassign(self, task_id, new_assignee_id) -> Task:
        return self.assign(task_id, new_assignee_id)

    def unassign(self, task_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.index_unassign(task.assignee_id, task_id)
            task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if deadline is not None:
                project = self._ctx.require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._ctx.require_task(task_id)
            now = self._ctx.now()

            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return _clone(task)


class _MessageStore(_BaseStore):
    def post(self, author_id, body, project_id=None, task_id=None,
             parent_id=None, attachments=None) -> Message:
        with self._lock:
            targets = [t for t in (project_id, task_id) if t is not None]
            if len(targets) != 1:
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            text = body if isinstance(body, str) else ""
            has_attachments = bool(attachments)
            if not text.strip() and not has_attachments:
                raise ValidationError("message body or attachment required")

            self._ctx.require_user(author_id)
            if project_id is not None:
                self._ctx.require_project(project_id)
            if task_id is not None:
                self._ctx.require_task(task_id)
            if parent_id is not None:
                self._ctx.require_message(parent_id)

            now = self._ctx.now()
            message = Message(
                id=self._ctx.next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=[],
                created_at=now,
                edited_at=None,
            )
            for item in (attachments or []):
                filename, data = item
                message.attachments.append(
                    self._build_attachment(filename, data, author_id, now)
                )
            self._ctx.messages[message.id] = message
            return _clone(message)

    @staticmethod
    def _build_attachment(filename, data, author_id, when) -> Attachment:
        if not isinstance(filename, str) or not filename.strip():
            raise ValidationError("attachment filename must not be empty")
        payload = data if data is not None else b""
        try:
            size = len(payload)
        except TypeError:
            raise ValidationError("attachment data must be sized")
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=author_id,
            uploaded_at=when,
        )

    def edit(self, message_id, author_id, new_body) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError("only the author may edit a message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body must not be empty")
            message.body = new_body
            message.edited_at = self._ctx.now()
            return _clone(message)

    def add_attachment(self, message_id, author_id, filename, data) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            attachment = self._build_attachment(
                filename, data, author_id, self._ctx.now()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._ctx.require_project(project_id)
            messages = [
                msg for msg in self._ctx.messages.values()
                if msg.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return _clone_list(messages)

    def list_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._ctx.require_task(task_id)
            messages = [
                msg for msg in self._ctx.messages.values()
                if msg.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return _clone_list(messages)

    def delete(self, message_id, author_id) -> None:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != author_id:
                raise AuthorizationError("only the author may delete a message")
            del self._ctx.messages[message_id]


class _PerformanceStore(_BaseStore):
    def completion_rate(self, user_id) -> float:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._ctx.require_user(user_id)
            durations = self._durations(self._ctx.tasks_for_assignee(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                delta = task.completed_at - task.started_at
                durations.append(delta.total_seconds())
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                      task_id=None) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._ctx.require_user(rater_id)
            self._ctx.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user may not rate themselves")
            if task_id is not None:
                self._ctx.require_task(task_id)

            rating = Rating(
                id=self._ctx.next_rating_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._ctx.now(),
            )
            self._ctx.ratings.append(rating)
            return _clone(rating)

    def _ratings_for(self, user_id) -> List[Rating]:
        return [r for r in self._ctx.ratings if r.ratee_id == user_id]

    def ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": _clone_list(ratings),
            }

    def user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._durations(tasks)
            avg_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


class _ReportStore(_BaseStore):
    @staticmethod
    def _status_counts(tasks) -> Dict[str, int]:
        counts = {status.value: 0 for status in TaskStatus}
        for task in tasks:
            counts[task.status.value] += 1
        return counts

    @staticmethod
    def _is_overdue(task, now) -> bool:
        return (
            task.deadline is not None
            and task.status != TaskStatus.COMPLETED
            and task.deadline < now
        )

    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            project = self._ctx.require_project(project_id)
            tasks = [
                t for t in self._ctx.tasks.values()
                if t.project_id == project_id
            ]
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            now = self._ctx.now()
            overdue = sum(1 for t in tasks if self._is_overdue(t, now))

            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total_tasks": 0, "completed_tasks": 0},
                )
                bucket["total_tasks"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed_tasks"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "completed_tasks": completed,
                "status_counts": self._status_counts(tasks),
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _user_row(self, user, tasks) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = _PerformanceStore._durations(tasks)
        avg_time = sum(durations) / len(durations) if durations else None
        return {
            "user_id": user.id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": avg_time,
        }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._ctx.require_project(project_id)
                scoped = [
                    t for t in self._ctx.tasks.values()
                    if t.project_id == project_id
                ]
            else:
                scoped = list(self._ctx.tasks.values())

            by_user: Dict[int, List[Task]] = {}
            for task in scoped:
                if task.assignee_id is None:
                    continue
                by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                user = self._ctx.users.get(user_id)
                if user is None:
                    continue
                rows.append(self._user_row(user, by_user[user_id]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            user = self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = _PerformanceStore._durations(tasks)
            avg_time = sum(durations) / len(durations) if durations else None

            task_rows = []
            for task in tasks:
                task_rows.append({
                    "task_id": task.id,
                    "project_id": task.project_id,
                    "title": task.title,
                    "status": task.status.value,
                    "deadline": task.deadline,
                    "started_at": task.started_at,
                    "completed_at": task.completed_at,
                })

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "tasks": task_rows,
            }

    # -- export ------------------------------------------------------------
    def export(self, report, fmt):
        with self._lock:
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("format must be a ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("report must be a mapping")
            if fmt == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    @staticmethod
    def _stringify(value) -> str:
        if isinstance(value, enum.Enum):
            return str(value.value)
        if isinstance(value, datetime):
            return value.isoformat()
        return str(value)

    def _to_csv(self, report) -> str:
        out = io.StringIO()
        writer = csv.writer(out)
        rows = report.get("rows")
        if (isinstance(rows, list) and rows
                and all(isinstance(r, dict) for r in rows)):
            header: List[str] = []
            for row in rows:
                for key in row:
                    if key not in header:
                        header.append(key)
            writer.writerow(header)
            for row in rows:
                writer.writerow(
                    [self._stringify(row.get(key, "")) for key in header]
                )
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._stringify(value)])
        return out.getvalue()

    def _to_pdf(self, report) -> bytes:
        return _build_pdf(self._report_to_text(report))

    def _report_to_text(self, report) -> List[str]:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, self._stringify(value)))
        return lines


# ---------------------------------------------------------------------------
# Minimal PDF rendering (standard library only)
# ---------------------------------------------------------------------------
def _build_pdf(lines: List[str]) -> bytes:
    """Render a tiny, structurally valid single-page PDF document."""

    def escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    safe_lines = lines if lines else [""]
    content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
    for index, line in enumerate(safe_lines):
        if index > 0:
            content_parts.append("T*")
        content_parts.append("({0}) Tj".format(escape(line)))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        (
            b"<< /Length " + str(len(content)).encode("latin-1") + b" >>\n"
            b"stream\n" + content + b"\nendstream"
        ),
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, obj in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(number).encode("latin-1") + b" 0 obj\n"
        pdf += obj + b"\nendobj\n"

    xref_pos = len(pdf)
    size = len(objects) + 1
    pdf += b"xref\n0 " + str(size).encode("latin-1") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += ("%010d 00000 n \n" % offset).encode("latin-1")
    pdf += b"trailer\n<< /Size " + str(size).encode("latin-1")
    pdf += b" /Root 1 0 R >>\n"
    pdf += b"startxref\n" + str(xref_pos).encode("latin-1") + b"\n%%EOF\n"
    return bytes(pdf)


